// Define the 5 sheets to chart — gids match the existing Tool_ nodes
return [
  { json: { sheetName: 'demand_global',      gid: 1545992731, chartType: 'line_volume'     } },
  { json: { sheetName: 'demand_transaction', gid: 996643932,  chartType: 'bar_segments'    } },
  { json: { sheetName: 'demand_asset',       gid: 219092738,  chartType: 'bar_stacked'     } },
  { json: { sheetName: 'ranking_global_war', gid: 232829744,  chartType: 'line_rank'       } },
  { json: { sheetName: 'audience',           gid: 1576889957, chartType: 'doughnut'        } }
];

// Collect all rows that came from Read Sheet for Chart
// Each item has the sheet's row data + the sheetName/gid/chartType from Define Chart Sheets
// n8n passes input items paired with the loop item — we group by sheetName
const items = $input.all();

// sheetName and chartType are carried via pairedItem from Define Chart Sheets
// but since googleSheets read replaces json with row data, we retrieve from $('Define Chart Sheets')
const meta = $('Define Chart Sheets').all();

// Group rows by their position in the meta array (each batch corresponds to one sheet)
// Use the row count per sheet to reconstruct grouping
// Simpler: trust that all items share the same sheetName in this execution branch
// because the loop runs one sheet at a time
const sheetName = meta.length === 1 ? meta[0].json.sheetName : (items[0]?.json?.sheetName ?? 'unknown');
const chartType = meta.length === 1 ? meta[0].json.chartType : 'bar_generic';

const rows = items.map(i => i.json);

return [{ json: { sheetName, chartType, rows } }];

const { sheetName, chartType, rows } = $input.first().json;

const distinct = arr => [...new Set(arr)].sort();
const palette  = ['#4285F4','#EA4335','#FBBC05','#34A853','#9C27B0','#FF6D00','#00ACC1'];
const short    = (s, n=18) => s && String(s).length > n ? String(s).slice(0,n)+'…' : String(s||'');

let chartConfig = null;

// ── demand_global: line chart volume over time ───────────────────────────────
if (chartType === 'line_volume') {
  const slice  = rows.slice(-24);
  const keys   = Object.keys(slice[0] || {});
  const dateK  = keys.find(k => /date|mois|month/i.test(k)) || keys[0];
  const volK   = keys.find(k => /volume|click|impres/i.test(k) && k !== dateK) || keys[1];

  chartConfig = {
    type: 'line',
    data: {
      labels: slice.map(r => r[dateK]),
      datasets: [{
        label: 'Search Volume',
        data: slice.map(r => Number(r[volK]) || 0),
        fill: true,
        backgroundColor: 'rgba(66,133,244,0.12)',
        borderColor: '#4285F4',
        borderWidth: 2,
        pointRadius: 3,
        tension: 0.35
      }]
    },
    options: {
      plugins: { title: { display: true, text: 'Demand Global — Monthly Volume', font: { size: 15 } } },
      scales:  { y: { beginAtZero: false } }
    }
  };
}

// ── demand_transaction: grouped bar by segment ───────────────────────────────
else if (chartType === 'bar_segments') {
  const keys   = Object.keys(rows[0] || {});
  const dateK  = keys.find(k => /date|mois/i.test(k))  || keys[0];
  const segK   = keys.find(k => /segment|transaction/i.test(k)) || keys[1];
  const volK   = keys.find(k => /volume|click/i.test(k)) || keys[2];

  const dates    = distinct(rows.map(r => r[dateK])).slice(-12);
  const segments = distinct(rows.map(r => r[segK]));

  chartConfig = {
    type: 'bar',
    data: {
      labels: dates,
      datasets: segments.map((seg, i) => ({
        label: short(seg),
        data: dates.map(d => {
          const m = rows.find(r => r[dateK] === d && r[segK] === seg);
          return m ? Number(m[volK]) || 0 : 0;
        }),
        backgroundColor: palette[i % palette.length]
      }))
    },
    options: {
      plugins: { title: { display: true, text: 'Demand by Transaction Segment', font: { size: 15 } } },
      scales:  { x: { stacked: false }, y: { stacked: false, beginAtZero: true } }
    }
  };
}

// ── demand_asset: stacked bar by asset type ──────────────────────────────────
else if (chartType === 'bar_stacked') {
  const keys   = Object.keys(rows[0] || {});
  const dateK  = keys.find(k => /date|mois/i.test(k))   || keys[0];
  const assetK = keys.find(k => /asset|type|bien/i.test(k)) || keys[1];
  const volK   = keys.find(k => /volume|click/i.test(k))    || keys[2];

  const dates  = distinct(rows.map(r => r[dateK])).slice(-12);
  const assets = distinct(rows.map(r => r[assetK]));

  chartConfig = {
    type: 'bar',
    data: {
      labels: dates,
      datasets: assets.map((a, i) => ({
        label: short(a),
        data: dates.map(d => {
          const m = rows.find(r => r[dateK] === d && r[assetK] === a);
          return m ? Number(m[volK]) || 0 : 0;
        }),
        backgroundColor: palette[i % palette.length]
      }))
    },
    options: {
      plugins: { title: { display: true, text: 'Demand by Asset Type', font: { size: 15 } } },
      scales:  { x: { stacked: true }, y: { stacked: true, beginAtZero: true } }
    }
  };
}

// ── ranking_global_war: multi-line rank (lower = better) ─────────────────────
else if (chartType === 'line_rank') {
  const keys   = Object.keys(rows[0] || {});
  const dateK  = keys.find(k => /date|mois/i.test(k)) || keys[0];
  const hostK  = keys.find(k => /host|url|domain/i.test(k)) || keys[1];
  const rankK  = keys.find(k => /rank|rang|position|war/i.test(k)) || keys[2];

  const dates = distinct(rows.map(r => r[dateK])).slice(-12);
  const hosts = distinct(rows.map(r => r[hostK]));

  chartConfig = {
    type: 'line',
    data: {
      labels: dates,
      datasets: hosts.map((h, i) => ({
        label: short(h, 22),
        data: dates.map(d => {
          const m = rows.find(r => r[dateK] === d && r[hostK] === h);
          return m ? Number(m[rankK]) || null : null;
        }),
        borderColor: palette[i % palette.length],
        backgroundColor: 'transparent',
        borderWidth: 2,
        pointRadius: 3,
        tension: 0.3,
        spanGaps: true
      }))
    },
    options: {
      plugins: { title: { display: true, text: 'SEO Ranking — Competitors (lower = better)', font: { size: 15 } } },
      scales:  { y: { reverse: true, beginAtZero: false } }
    }
  };
}

// ── audience: doughnut brand / non-brand / anonymous ─────────────────────────
else if (chartType === 'doughnut') {
  const keys      = Object.keys(rows[0] || {});
  const typeK     = keys.find(k => /type|segment|audience/i.test(k)) || keys[0];
  const clickK    = keys.find(k => /click|volume/i.test(k)) || keys[1];

  const totals = {};
  for (const r of rows) {
    const t = String(r[typeK] || 'unknown').toLowerCase();
    totals[t] = (totals[t] || 0) + (Number(r[clickK]) || 0);
  }
  const labels = Object.keys(totals);
  const data   = labels.map(l => totals[l]);
  const bg     = labels.map((_, i) => palette[i % palette.length]);

  chartConfig = {
    type: 'doughnut',
    data: {
      labels,
      datasets: [{ data, backgroundColor: bg, borderWidth: 2 }]
    },
    options: {
      plugins: {
        title:  { display: true, text: 'Audience — Brand vs Non-brand vs Anonymous', font: { size: 15 } },
        legend: { position: 'bottom' }
      }
    }
  };
}

// ── Generic fallback ─────────────────────────────────────────────────────────
if (!chartConfig) {
  const k = Object.keys(rows[0] || {});
  chartConfig = {
    type: 'bar',
    data: {
      labels: rows.map(r => short(r[k[0]])),
      datasets: [{ label: k[1], data: rows.map(r => Number(r[k[1]]) || 0), backgroundColor: '#4285F4' }]
    },
    options: { plugins: { title: { display: true, text: sheetName, font: { size: 15 } } } }
  };
}

return [{ json: { sheetName, chartConfig } }];

// Re-attach sheetName and rename binary key to 'data' (required by Google Drive upload)
const sheetName = $('Build Chart Config').first().json.sheetName;
const item = $input.first();
const binary = { data: item.binary.chartImage };
return [{ json: { sheetName }, binary }];
